import React, { useState, useEffect, createContext, useContext, useCallback } from 'react';
import ReactDOM from 'react-dom/client';

// OAuth Configuration
const OAUTH_CONFIG = {
  clientId: process.env.REACT_APP_OAUTH_CLIENT_ID || 'your-client-id',
  clientSecret: process.env.REACT_APP_OAUTH_CLIENT_SECRET || '',
  authorizationEndpoint: process.env.REACT_APP_AUTH_ENDPOINT || 'https://auth.example.com/authorize',
  tokenEndpoint: process.env.REACT_APP_TOKEN_ENDPOINT || 'https://auth.example.com/oauth/token',
  redirectUri: process.env.REACT_APP_REDIRECT_URI || window.location.origin + '/callback',
  scope: process.env.REACT_APP_OAUTH_SCOPE || 'openid profile email',
  apiBaseUrl: process.env.REACT_APP_API_BASE_URL || 'https://api.example.com',
};

// PKCE Helper Functions
function generateRandomString(length) {
  const charset = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-._~';
  const array = new Uint8Array(length);
  crypto.getRandomValues(array);
  return Array.from(array, (byte) => charset[byte % charset.length]).join('');
}

async function generateCodeChallenge(codeVerifier) {
  const encoder = new TextEncoder();
  const data = encoder.encode(codeVerifier);
  const digest = await crypto.subtle.digest('SHA-256', data);
  return btoa(String.fromCharCode(...new Uint8Array(digest)))
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/, '');
}

// Token Storage Utilities
const TokenStorage = {
  getAccessToken: () => localStorage.getItem('oauth_access_token'),
  getRefreshToken: () => localStorage.getItem('oauth_refresh_token'),
  getTokenExpiry: () => localStorage.getItem('oauth_token_expiry'),
  getIdToken: () => localStorage.getItem('oauth_id_token'),

  setTokens: ({ access_token, refresh_token, expires_in, id_token }) => {
    if (access_token) localStorage.setItem('oauth_access_token', access_token);
    if (refresh_token) localStorage.setItem('oauth_refresh_token', refresh_token);
    if (id_token) localStorage.setItem('oauth_id_token', id_token);
    if (expires_in) {
      const expiry = Date.now() + expires_in * 1000;
      localStorage.setItem('oauth_token_expiry', expiry.toString());
    }
  },

  clearTokens: () => {
    localStorage.removeItem('oauth_access_token');
    localStorage.removeItem('oauth_refresh_token');
    localStorage.removeItem('oauth_token_expiry');
    localStorage.removeItem('oauth_id_token');
    localStorage.removeItem('oauth_code_verifier');
    localStorage.removeItem('oauth_state');
  },

  isTokenExpired: () => {
    const expiry = localStorage.getItem('oauth_token_expiry');
    if (!expiry) return true;
    return Date.now() >= parseInt(expiry, 10) - 60000; // 1 minute buffer
  },
};

// Authenticated Fetch Wrapper
async function authenticatedFetch(url, options = {}, authContext) {
  let accessToken = TokenStorage.getAccessToken();

  if (TokenStorage.isTokenExpired()) {
    const refreshToken = TokenStorage.getRefreshToken();
    if (refreshToken) {
      try {
        const newTokens = await refreshAccessToken(refreshToken);
        TokenStorage.setTokens(newTokens);
        accessToken = newTokens.access_token;
        if (authContext && authContext.setUser) {
          authContext.setIsAuthenticated(true);
        }
      } catch (error) {
        TokenStorage.clearTokens();
        if (authContext) {
          authContext.setIsAuthenticated(false);
          authContext.setUser(null);
        }
        throw new Error('Session expired. Please log in again.');
      }
    } else {
      throw new Error('No refresh token available. Please log in.');
    }
  }

  const fullUrl = url.startsWith('http') ? url : `${OAUTH_CONFIG.apiBaseUrl}${url}`;

  const response = await fetch(fullUrl, {
    ...options,
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${accessToken}`,
      ...options.headers,
    },
  });

  if (response.status === 401) {
    const refreshToken = TokenStorage.getRefreshToken();
    if (refreshToken) {
      try {
        const newTokens = await refreshAccessToken(refreshToken);
        TokenStorage.setTokens(newTokens);
        return fetch(fullUrl, {
          ...options,
          headers: {
            'Content-Type': 'application/json',
            Authorization: `Bearer ${newTokens.access_token}`,
            ...options.headers,
          },
        });
      } catch {
        TokenStorage.clearTokens();
        throw new Error('Session expired. Please log in again.');
      }
    }
  }

  return response;
}

// OAuth Flow Functions
async function initiateAuthorizationFlow() {
  const state = generateRandomString(32);
  const codeVerifier = generateRandomString(64);
  const codeChallenge = await generateCodeChallenge(codeVerifier);

  localStorage.setItem('oauth_state', state);
  localStorage.setItem('oauth_code_verifier', codeVerifier);

  const params = new URLSearchParams({
    response_type: 'code',
    client_id: OAUTH_CONFIG.clientId,
    redirect_uri: OAUTH_CONFIG.redirectUri,
    scope: OAUTH_CONFIG.scope,
    state: state,
    code_challenge: codeChallenge,
    code_challenge_method: 'S256',
  });

  window.location.href = `${OAUTH_CONFIG.authorizationEndpoint}?${params.toString()}`;
}

async function exchangeCodeForTokens(code) {
  const codeVerifier = localStorage.getItem('oauth_code_verifier');

  const body = new URLSearchParams({
    grant_type: 'authorization_code',
    code: code,
    redirect_uri: OAUTH_CONFIG.redirectUri,
    client_id: OAUTH_CONFIG.clientId,
    code_verifier: codeVerifier,
  });

  if (OAUTH_CONFIG.clientSecret) {
    body.append('client_secret', OAUTH_CONFIG.clientSecret);
  }

  const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: body.toString(),
  });

  if (!response.ok) {
    const errorData = await response.json().catch(() => ({}));
    throw new Error(errorData.error_description || 'Failed to exchange authorization code for tokens');
  }

  const tokens = await response.json();

  localStorage.removeItem('oauth_code_verifier');
  localStorage.removeItem('oauth_state');

  return tokens;
}

async function refreshAccessToken(refreshToken) {
  const body = new URLSearchParams({
    grant_type: 'refresh_token',
    refresh_token: refreshToken,
    client_id: OAUTH_CONFIG.clientId,
  });

  if (OAUTH_CONFIG.clientSecret) {
    body.append('client_secret', OAUTH_CONFIG.clientSecret);
  }

  const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: body.toString(),
  });

  if (!response.ok) {
    throw new Error('Failed to refresh access token');
  }

  return response.json();
}

function parseJwt(token) {
  try {
    const base64Url = token.split('.')[1];
    const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
    const jsonPayload = decodeURIComponent(
      atob(base64)
        .split('')
        .map((c) => '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2))
        .join('')
    );
    return JSON.parse(jsonPayload);
  } catch {
    return null;
  }
}

