const AuthContext = createContext(null);

function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

// Auth Provider Component
function AuthProvider({ children }) {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const extractUserFromToken = useCallback(() => {
    const idToken = TokenStorage.getIdToken();
    const accessToken = TokenStorage.getAccessToken();
    const token = idToken || accessToken;
    if (token) {
      const decoded = parseJwt(token);
      if (decoded) {
        setUser({
          sub: decoded.sub,
          name: decoded.name || decoded.preferred_username || 'User',
          email: decoded.email || '',
          picture: decoded.picture || '',
          ...decoded,
        });
        return true;
      }
    }
    return false;
  }, []);

  useEffect(() => {
    const initAuth = async () => {
      try {
        const accessToken = TokenStorage.getAccessToken();
        if (accessToken && !TokenStorage.isTokenExpired()) {
          extractUserFromToken();
          setIsAuthenticated(true);
        } else if (TokenStorage.getRefreshToken()) {
          try {
            const newTokens = await refreshAccessToken(TokenStorage.getRefreshToken());
            TokenStorage.setTokens(newTokens);
            extractUserFromToken();
            setIsAuthenticated(true);
          } catch {
            TokenStorage.clearTokens();
            setIsAuthenticated(false);
          }
        }
      } catch (err) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };

    initAuth();
  }, [extractUserFromToken]);

  const login = useCallback(() => {
    initiateAuthorizationFlow();
  }, []);

  const logout = useCallback(() => {
    TokenStorage.clearTokens();
    setIsAuthenticated(false);
    setUser(null);
    setError(null);
  }, []);

  const handleCallback = useCallback(
    async (code, state) => {
      setLoading(true);
      setError(null);

      try {
        const savedState = localStorage.getItem('oauth_state');
        if (state !== savedState) {
          throw new Error('State mismatch. Possible CSRF attack.');
        }

        const tokens = await exchangeCodeForTokens(code);
        TokenStorage.setTokens(tokens);
        extractUserFromToken();
        setIsAuthenticated(true);

        return true;
      } catch (err) {
        setError(err.message);
        TokenStorage.clearTokens();
        setIsAuthenticated(false);
        return false;
      } finally {
        setLoading(false);
      }
    },
    [extractUserFromToken]
  );

  const apiFetch = useCallback(
    (url, options) => {
      return authenticatedFetch(url, options, { setIsAuthenticated, setUser });
    },
    []
  );

  const value = {
    isAuthenticated,
    user,
    loading,
    error,
    login,
    logout,
    handleCallback,
    apiFetch,
    setIsAuthenticated,
    setUser,
  };

  return React.createElement(AuthContext.Provider, { value }, children);
}

// Simple Router
function useRoute() {
  const [path, setPath] = useState(window.location.pathname);

  useEffect(() => {
    const handlePopState = () => setPath(window.location.pathname);
    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  const navigate = useCallback((newPath) => {
    window.history.pushState({}, '', newPath);
    setPath(newPath);
  }, []);

  return { path, navigate };
}

